     fn previous_window(&mut self) {
         if !self.windows.is_empty() {
+            self.clear_visual_selection();
             self.active_window = if self.active_window == 0 {
                 self.windows.len() - 1
             } else {
                 self.active_window - 1
             };
         }
     }

