+fn ordered_rows(selection: VisualSelection) -> (usize, usize) {
+    if selection.anchor.row <= selection.cursor.row {
+        (selection.anchor.row, selection.cursor.row)
+    } else {
+        (selection.cursor.row, selection.anchor.row)
+    }
+}
+
+fn selection_columns_for_line(
+    selection: VisualSelection,
+    row: usize,
+    line: &str,
+) -> (usize, usize) {
+    let line_len = line.chars().count();
+    let (start_row, end_row) = ordered_rows(selection);
+    if row < start_row || row > end_row {
+        return (0, 0);
+    }
+
+    let (start, end) = match selection.kind {
+        VisualSelectionKind::Line => (0, line_len),
+        VisualSelectionKind::Block => {
+            let start = selection.anchor.column.min(selection.cursor.column);
+            let end = selection.anchor.column.max(selection.cursor.column) + 1;
+            (start, end)
+        }
+        VisualSelectionKind::Character if selection.anchor.row == selection.cursor.row => {
+            let start = selection.anchor.column.min(selection.cursor.column);
+            let end = selection.anchor.column.max(selection.cursor.column) + 1;
+            (start, end)
+        }
+        VisualSelectionKind::Character if row == start_row => {
+            let start = if selection.anchor.row <= selection.cursor.row {
+                selection.anchor.column
+            } else {
+                selection.cursor.column
+            };
+            (start, line_len)
+        }
+        VisualSelectionKind::Character if row == end_row => {
+            let end = if selection.anchor.row <= selection.cursor.row {
+                selection.cursor.column
+            } else {
+                selection.anchor.column
+            } + 1;
+            (0, end)
+        }
+        VisualSelectionKind::Character => (0, line_len),
+    };
+
+    (start.min(line_len), end.min(line_len))
+}
+
+fn pane_text_lines(text: &str) -> Vec<&str> {
+    if text.is_empty() {
+        vec![""]
+    } else {
+        text.split('\n').collect()
+    }
+}
+
+fn selectable_right_text_lines(text: &str) -> Vec<&str> {
+    let mut lines = pane_text_lines(text);
+    if lines.last().is_some_and(|line| line.starts_with("chat> ")) {
+        lines.pop();
+    }
+    lines
+}
+
+fn right_text_has_chat_prompt(text: &str) -> bool {
+    pane_text_lines(text)
+        .last()
+        .is_some_and(|line| line.starts_with("chat> "))
+}
+
+fn clamp_column_for_line(line: &str, column: usize) -> usize {
+    let line_len = line.chars().count();
+    if line_len == 0 {
+        0
+    } else {
+        column.min(line_len.saturating_sub(1))
+    }
+}
+
+fn char_slice(text: &str, start: usize, end: usize) -> String {
+    text.chars()
+        .skip(start)
+        .take(end.saturating_sub(start))
+        .collect()
+}
+
+fn osc52_clipboard_sequence(text: &str) -> String {
+    format!("\u{1b}]52;c;{}\u{7}", base64_encode(text.as_bytes()))
+}
+
+fn base64_encode(bytes: &[u8]) -> String {
+    const TABLE: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
+    let mut encoded = String::with_capacity(bytes.len().div_ceil(3) * 4);
+    for chunk in bytes.chunks(3) {
+        let b0 = chunk[0];
+        let b1 = *chunk.get(1).unwrap_or(&0);
+        let b2 = *chunk.get(2).unwrap_or(&0);
+
+        encoded.push(TABLE[(b0 >> 2) as usize] as char);
+        encoded.push(TABLE[(((b0 & 0b0000_0011) << 4) | (b1 >> 4)) as usize] as char);
+        if chunk.len() > 1 {
+            encoded.push(TABLE[(((b1 & 0b0000_1111) << 2) | (b2 >> 6)) as usize] as char);
+        } else {
+            encoded.push('=');
+        }
+        if chunk.len() > 2 {
+            encoded.push(TABLE[(b2 & 0b0011_1111) as usize] as char);
+        } else {
+            encoded.push('=');
+        }
+    }
+    encoded
+}
